'use client'
import { useEffect, useState } from 'react'
import { timeAgo } from '@/lib/utils'

interface ThreatPoint {
  type: string; country: string; lat: number; lng: number; severity: number; label: string
  srcCountry?: string; dstCountry?: string; srcLat?: number; srcLng?: number; dstLat?: number; dstLng?: number
  details?: string; sourceUrl?: string; createdAt?: string
}

interface Pulse {
  id: string; name: string; tags: string[]; targeted_countries: string[]
  malware_families: string[]; adversary: string; tlp: string; created: string; modified: string
}

const TYPE_COLOR: Record<string, string> = {
  Ransomware:'#ff3a5c', APT:'#a78bfa', Phishing:'#ff8c42',
  DDoS:'#ffd700', Malware:'#ff3a5c', Scanner:'#00aaff', Threat:'#64748b',
}

const W = 900, H = 460
function project(lat: number, lng: number): [number, number] {
  return [((lng + 180) / 360) * W, ((90 - lat) / 180) * H]
}

const CONTINENTS = [
  'M 150 60 L 258 52 L 275 115 L 245 162 L 215 205 L 188 215 L 167 178 L 145 138 Z',
  'M 200 225 L 262 218 L 282 285 L 270 368 L 238 390 L 206 365 L 196 305 Z',
  'M 395 52 L 478 46 L 488 105 L 460 122 L 418 110 L 398 80 Z',
  'M 400 128 L 480 120 L 508 180 L 496 298 L 458 328 L 420 306 L 400 245 L 398 178 Z',
  'M 478 38 L 738 28 L 762 88 L 740 175 L 686 205 L 615 190 L 558 155 L 482 122 L 478 65 Z',
  'M 478 28 L 738 12 L 752 52 L 478 48 Z',
  'M 648 270 L 728 258 L 748 308 L 715 332 L 672 320 L 652 295 Z',
]

export default function ThreatMapPage() {
  const [points, setPoints]   = useState<ThreatPoint[]>([])
  const [pulses, setPulses]   = useState<Pulse[]>([])
  const [selected, setSelected] = useState<ThreatPoint | null>(null)
  const [loading,  setLoading]  = useState(true)
  const [filter,   setFilter]   = useState('ALL')
  const [stats, setStats]       = useState({ total: 0, critical: 0, activeCVEs: 0, cveIds: [] as string[] })

  async function load() {
    setLoading(true)
    const [ptRes, pulseRes, statRes] = await Promise.all([
      fetch('/api/v1/threat?limit=80'),
      fetch('/api/v1/threat?view=pulses&limit=15'),
      fetch('/api/v1/threat?view=stats'),
    ])
    const [ptData, pulseData, statData] = await Promise.all([ptRes.json(), pulseRes.json(), statRes.json()])
    setPoints(Array.isArray(ptData) ? ptData : [])
    setPulses(Array.isArray(pulseData) ? pulseData : [])
    setStats(statData ?? { total: 0, critical: 0, activeCVEs: 0, cveIds: [] })
    setLoading(false)
  }

  useEffect(() => { load() }, [])
  useEffect(() => { const iv = setInterval(load, 60_000); return () => clearInterval(iv) }, [])

  const types   = ['ALL', ...Array.from(new Set(points.map(p => p.type)))]
  const visible = points.filter(p => filter === 'ALL' || p.type === filter)
  const grouped = visible.reduce((a, p) => ({ ...a, [p.type]: (a[p.type] ?? 0) + 1 }), {} as Record<string, number>)

  return (
    <div className="p-5 space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black">Global Threat <span className="text-accent">Map</span></h1>
          <p className="font-mono text-[11px] text-slate-500 mt-0.5">
            AlienVault OTX · {points.length} events · auto-refresh 60s
          </p>
        </div>
        <button onClick={load} className="font-mono text-[10px] px-3 py-2 rounded-lg border border-white/[0.08] text-slate-500 hover:text-accent hover:border-accent/25 transition-all">
          ↻ REFRESH
        </button>
      </div>

      {/* Stats */}
      <div className="flex gap-2 flex-wrap">
        {[
          { label:'Total Events', v: stats.total || points.length, c:'#00ffaa' },
          { label:'Critical',     v: stats.critical || visible.filter(p => p.severity >= 4).length, c:'#ff3a5c' },
          { label:'Active CVEs',  v: stats.activeCVEs || stats.cveIds?.length || 0, c:'#a78bfa' },
          ...Object.entries(grouped).slice(0,3).map(([t,n]) => ({ label:t, v:n, c: TYPE_COLOR[t] ?? '#64748b' })),
        ].map((s,i) => (
          <div key={i} className="glass-sm px-3 py-2 flex items-center gap-2">
            <span className="font-mono text-lg font-bold" style={{ color:s.c }}>{s.v}</span>
            <span className="font-mono text-[9px] text-slate-600 uppercase tracking-wider">{s.label}</span>
          </div>
        ))}
      </div>

      {/* Filter */}
      <div className="flex gap-1.5 flex-wrap">
        {types.map(t => (
          <button key={t} onClick={() => setFilter(t)}
            className={`font-mono text-[10px] px-3 py-1.5 rounded border transition-all
              ${filter === t ? 'border-accent/30 text-accent bg-accent/8' : 'border-white/[0.08] text-slate-500 hover:text-slate-300'}`}>
            {t}{t !== 'ALL' && grouped[t] ? ` (${grouped[t]})` : ''}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-[1fr_320px] gap-4">
        {/* Map */}
        <div className="glass overflow-hidden">
          <div className="relative" style={{ background: '#04080f' }}>
            {loading && (
              <div className="absolute inset-0 flex items-center justify-center z-10 bg-black/40">
                <span className="font-mono text-[12px] text-accent animate-pulse">Fetching OTX data...</span>
              </div>
            )}
            <svg viewBox={`0 0 ${W} ${H}`} className="w-full" style={{ display:'block' }}>
              {[-60,-30,0,30,60].map(lat => { const [,y]=project(lat,0); return <line key={lat} x1={0} y1={y} x2={W} y2={y} stroke="rgba(0,255,170,0.04)" strokeWidth={0.5}/> })}
              {[-120,-60,0,60,120].map(lng => { const [x]=project(0,lng); return <line key={lng} x1={x} y1={0} x2={x} y2={H} stroke="rgba(0,255,170,0.04)" strokeWidth={0.5}/> })}
              {CONTINENTS.map((d,i) => <path key={i} d={d} fill="rgba(0,255,170,0.055)" stroke="rgba(0,255,170,0.12)" strokeWidth={0.5}/>)}

              {visible.map((pt, i) => {
                const lat = pt.srcLat ?? pt.lat
                const lng = pt.srcLng ?? pt.lng
                if (!lat && !lng) return null
                const [x, y] = project(lat, lng)
                const color  = TYPE_COLOR[pt.type] ?? '#64748b'
                const r      = (pt.severity ?? 3) >= 4 ? 6 : 4
                const isSel  = selected === pt
                return (
                  <g key={i} style={{ cursor:'pointer' }} onClick={() => setSelected(isSel ? null : pt)}>
                    <circle cx={x} cy={y} r={r*3} fill={color} fillOpacity={0.06}/>
                    <circle cx={x} cy={y} r={r} fill={color} fillOpacity={isSel ? 1 : 0.85}
                      stroke={isSel ? '#fff' : 'none'} strokeWidth={isSel ? 1.5 : 0}/>
                    <circle cx={x} cy={y} r={r*2} fill="none" stroke={color} strokeWidth={0.8} strokeOpacity={0.25}/>
                    {/* Destination arc if available */}
                    {pt.dstLat && pt.dstLng && (() => {
                      const [dx, dy] = project(pt.dstLat, pt.dstLng)
                      const mx = (x + dx) / 2; const my = Math.min(y, dy) - Math.abs(dx - x) * 0.2
                      return <path d={`M${x} ${y} Q${mx} ${my} ${dx} ${dy}`} fill="none" stroke={color} strokeWidth={0.7} strokeOpacity={0.3} strokeDasharray="4 4"/>
                    })()}
                  </g>
                )
              })}
            </svg>

            <div className="absolute bottom-2 left-3 flex gap-3 flex-wrap">
              {Object.entries(TYPE_COLOR).slice(0,5).map(([t,c]) => (
                <div key={t} className="flex items-center gap-1">
                  <div className="w-1.5 h-1.5 rounded-full" style={{ background:c }}/>
                  <span className="font-mono text-[9px] text-slate-600">{t}</span>
                </div>
              ))}
            </div>

            {selected && (
              <div className="absolute top-3 right-3 glass-sm p-3 max-w-[220px]" onClick={() => setSelected(null)}>
                <div className="font-mono text-[9px] mb-1" style={{ color: TYPE_COLOR[selected.type] ?? '#64748b' }}>{selected.type}</div>
                <div className="font-mono text-[10px] text-accent mb-1">{selected.srcCountry ?? selected.country}</div>
                <div className="text-[11px] text-slate-400 line-clamp-2">{selected.details ?? selected.label}</div>
                <div className="flex gap-0.5 mt-1.5">
                  {Array.from({length:5}).map((_,j) => (
                    <div key={j} className="h-1 flex-1 rounded" style={{ background: j < (selected.severity??3) ? '#ff3a5c' : 'rgba(255,255,255,0.08)' }}/>
                  ))}
                </div>
                {selected.sourceUrl && <a href={selected.sourceUrl} target="_blank" rel="noreferrer" className="font-mono text-[9px] text-accent2 hover:underline mt-1 block">OTX ↗</a>}
              </div>
            )}
          </div>
        </div>

        {/* Pulse feed */}
        <div className="glass overflow-hidden">
          <div className="flex items-center gap-2 px-4 py-3 border-b border-white/[0.06]">
            <div className="live-dot"/>
            <span className="font-mono text-[11px] text-accent uppercase tracking-widest">OTX Pulses</span>
          </div>
          <div className="overflow-y-auto" style={{ maxHeight:'400px' }}>
            {pulses.length === 0 && <div className="p-8 text-center font-mono text-[11px] text-slate-600 animate-pulse">Loading OTX intelligence...</div>}
            {pulses.map(p => {
              const sev = p.tlp === 'red' ? '#ff3a5c' : p.tlp === 'amber' ? '#ff8c42' : '#64748b'
              return (
                <a key={p.id} href={`https://otx.alienvault.com/pulse/${p.id}`} target="_blank" rel="noreferrer"
                  className="block px-4 py-3 border-b border-white/[0.03] hover:bg-white/[0.03] transition-colors">
                  <div className="flex items-start gap-2">
                    <div className="w-[3px] self-stretch rounded-full shrink-0 mt-1" style={{ background:sev }}/>
                    <div className="flex-1 min-w-0">
                      <div className="text-[12px] font-semibold text-slate-200 line-clamp-2 mb-1">{p.name}</div>
                      <div className="flex gap-2 flex-wrap">
                        {p.targeted_countries?.slice(0,3).map(c => <span key={c} className="font-mono text-[9px] text-slate-600">{c}</span>)}
                        {p.adversary && <span className="font-mono text-[9px] text-orange-400">{p.adversary}</span>}
                      </div>
                      <div className="font-mono text-[9px] text-slate-700 mt-1">{timeAgo(p.modified ?? p.created)}</div>
                    </div>
                  </div>
                </a>
              )
            })}
          </div>

          {stats.cveIds?.length > 0 && (
            <div className="border-t border-white/[0.06] p-3">
              <div className="font-mono text-[9px] text-slate-600 uppercase tracking-widest mb-2">CVEs in OTX Pulses</div>
              <div className="flex flex-wrap gap-1.5">
                {stats.cveIds.slice(0,8).map((cve:string) => (
                  <a key={cve} href={`/cve?q=${cve}`} className="font-mono text-[9px] px-1.5 py-[2px] rounded border bg-purple-500/10 text-purple-400 border-purple-500/20 hover:bg-purple-500/20 transition-colors">
                    {cve}
                  </a>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
